from plateau import Plateau
from voiture import Voiture

def copier_plateau(plateau):
    nouveau = Plateau()
    for v in plateau.voiture:
        copie = Voiture(v.marque, v.x, v.y, v.taille, v.orient)
        nouveau.ajouter_voiture(copie)
    return nouveau

def etat(plateau):
    positions = []
    for v in plateau.voiture:
        positions.append((v.marque, v.x, v.y))
    return positions


def chercher_solutions(plateau_depart):
    deja_vus = []
    a_explorer = [(plateau_depart, [])]
    toutes_les_solutions = []

    while len(a_explorer) > 0:
        plateau_actuel, chemin = a_explorer.pop(0)

        if plateau_actuel.gagne():
            toutes_les_solutions.append(chemin)
            continue

        for voiture in plateau_actuel.voiture:
            for direction in ['left', 'right', 'up', 'down']:
                if voiture.mouvement_possible(plateau_actuel, direction):
                    nouveau_plateau = copier_plateau(plateau_actuel)
                    for v in nouveau_plateau.voiture:
                        if v.marque == voiture.marque:
                            if v.mouvement_possible(nouveau_plateau, direction):
                                for i in range(v.taille):
                                    if v.orient == 'horizontale':
                                        nouveau_plateau.grille[v.y][v.x + i] = None
                                    else:
                                        nouveau_plateau.grille[v.y + i][v.x] = None
                                v.deplacer(direction)
                                for i in range(v.taille):
                                    if v.orient == 'horizontale':
                                        nouveau_plateau.grille[v.y][v.x + i] = v
                                    else:
                                        nouveau_plateau.grille[v.y + i][v.x] = v
                                break
                    etat_actuel = etat(nouveau_plateau)
                    if etat_actuel not in deja_vus:
                        deja_vus.append(etat_actuel)
                        nouveau_chemin = chemin + [(voiture.marque, direction)]
                        a_explorer.append((nouveau_plateau, nouveau_chemin))

    return toutes_les_solutions
